import{_ as s,c as a,o as t,ae as n}from"./chunks/framework.Cd-3tpCq.js";const h=JSON.parse(`{"title":"Étape 1.2 — Découvrir l'interface visuelle de Canvas","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-canvas/interface.md","filePath":"drupal-canvas/interface.md"}`),o={name:"drupal-canvas/interface.md"};function r(i,e,l,p,d,u){return t(),a("div",null,e[0]||(e[0]=[n(`<h1 id="etape-1-2-—-decouvrir-l-interface-visuelle-de-canvas" tabindex="-1">Étape 1.2 — Découvrir l&#39;interface visuelle de Canvas <a class="header-anchor" href="#etape-1-2-—-decouvrir-l-interface-visuelle-de-canvas" aria-label="Permalink to &quot;Étape 1.2 — Découvrir l&#39;interface visuelle de Canvas&quot;">​</a></h1><h2 id="🗺️-vue-d-ensemble-de-l-interface" tabindex="-1">🗺️ Vue d&#39;ensemble de l&#39;interface <a class="header-anchor" href="#🗺️-vue-d-ensemble-de-l-interface" aria-label="Permalink to &quot;🗺️ Vue d&#39;ensemble de l&#39;interface&quot;">​</a></h2><p>Lorsque vous ouvrez ou créez une <strong>Canvas Page</strong>, vous accédez à l&#39;éditeur visuel <strong>Canvas</strong>. L&#39;interface est divisée en 3 grandes zones :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    BARRE D&#39;OUTILS (haut)                │</span></span>
<span class="line"><span>├──────────────────┬──────────────────┬───────────────────┤</span></span>
<span class="line"><span>│                  │                  │                   │</span></span>
<span class="line"><span>│   PANNEAU DE     │   ZONE CENTRALE  │   PANNEAU DE      │</span></span>
<span class="line"><span>│   GAUCHE         │                  │   DROITE          │</span></span>
<span class="line"><span>│                  │  Prévisualisation│                   │</span></span>
<span class="line"><span>│   Composants     │   en direct      │   Propriétés      │</span></span>
<span class="line"><span>│   disponibles    │                  │   du composant    │</span></span>
<span class="line"><span>│                  │                  │                   │</span></span>
<span class="line"><span>└──────────────────┴──────────────────┴───────────────────┘</span></span></code></pre></div><h2 id="🔵-zone-1-—-le-panneau-de-gauche-les-composants-disponibles" tabindex="-1">🔵 Zone 1 — Le panneau de gauche : les composants disponibles <a class="header-anchor" href="#🔵-zone-1-—-le-panneau-de-gauche-les-composants-disponibles" aria-label="Permalink to &quot;🔵 Zone 1 — Le panneau de gauche : les composants disponibles&quot;">​</a></h2><p>Le panneau de gauche est votre boîte à outils. C&#39;est ici que vous trouvez tous les composants que vous pouvez ajouter à votre page. Ce que vous y trouvez :</p><table tabindex="0"><thead><tr><th>Élément</th><th>Description</th></tr></thead><tbody><tr><td><strong>Bibliothèque de composants</strong></td><td>Tous les composants SDC disponibles dans votre thème</td></tr><tr><td><strong>Patterns</strong></td><td>Des assemblages de composants pré-construits et réutilisables</td></tr><tr><td><strong>Composants globaux</strong></td><td>Header, Footer, éléments partagés sur toutes les pages</td></tr><tr><td><strong>Barre de recherche</strong></td><td>Pour retrouver rapidement un composant par son nom</td></tr></tbody></table><p>Comment l&#39;utiliser :</p><ul><li>Parcourez les catégories de composants disponibles.</li><li>Recherchez un composant via la barre de recherche en haut du panneau.</li><li>Glissez-déposez (drag &amp; drop) un composant depuis le panneau vers la zone centrale.</li><li>Ou cliquez sur le composant pour l&#39;ajouter à la section active.</li></ul><div class="warning custom-block"><p class="custom-block-title">⚠️ A noter :</p><p>Les composants disponibles dépendent de ceux qui ont été développés dans votre thème. Avec le thème Mercury fraîchement généré, la liste est minimaliste au départ. C&#39;est normal, nous allons les créer ensemble dans les prochains modules !</p></div><h2 id="🟢-zone-2-—-la-zone-centrale-la-previsualisation-en-direct" tabindex="-1">🟢 Zone 2 — La zone centrale : la prévisualisation en direct <a class="header-anchor" href="#🟢-zone-2-—-la-zone-centrale-la-previsualisation-en-direct" aria-label="Permalink to &quot;🟢 Zone 2 — La zone centrale : la prévisualisation en direct&quot;">​</a></h2><p>La zone centrale est le cœur de Canvas. C&#39;est ici que vous construisez et visualisez votre page en temps réel.</p><h3 id="ses-caracteristiques" tabindex="-1">Ses caractéristiques : <a class="header-anchor" href="#ses-caracteristiques" aria-label="Permalink to &quot;Ses caractéristiques :&quot;">​</a></h3><ul><li>Ce que vous voyez ici est exactement ce que verra votre visiteur sur le site.</li><li>Les modifications sont instantanées : pas besoin de sauvegarder pour voir le résultat.</li><li>Vous pouvez cliquer directement sur un élément de la page pour le sélectionner et l&#39;éditer.</li></ul><h3 id="les-actions-disponibles-dans-la-zone-centrale" tabindex="-1">Les actions disponibles dans la zone centrale : <a class="header-anchor" href="#les-actions-disponibles-dans-la-zone-centrale" aria-label="Permalink to &quot;Les actions disponibles dans la zone centrale :&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Comment faire</th></tr></thead><tbody><tr><td><strong>Sélectionner un composant</strong></td><td>Clic sur le composant dans la prévisualisation</td></tr><tr><td><strong>Déplacer un composant</strong></td><td>Glisser-déposer vers le haut ou le bas</td></tr><tr><td><strong>Ajouter une section</strong></td><td>Cliquer sur le bouton + entre deux sections</td></tr><tr><td><strong>Supprimer un élément</strong></td><td>Sélectionner puis cliquer sur l&#39;icône 🗑️</td></tr><tr><td><strong>Dupliquer un élément</strong></td><td>Sélectionner puis cliquer sur l&#39;icône de copie</td></tr></tbody></table><h3 id="les-indicateurs-visuels" tabindex="-1">Les indicateurs visuels : <a class="header-anchor" href="#les-indicateurs-visuels" aria-label="Permalink to &quot;Les indicateurs visuels :&quot;">​</a></h3><p>Lorsque vous survolez ou sélectionnez un élément, Canvas affiche des indicateurs visuels colorés :</p><ul><li>🔵 Contour bleu → un composant est survolé.</li><li>🟠 Contour orange → un composant est sélectionné et éditable.</li><li>➕ Bouton + → zone où vous pouvez insérer un nouveau composant ou une section.</li></ul><div class="tip custom-block"><p class="custom-block-title">💡 Astuce</p><p>Vous pouvez basculer entre une vue Desktop, Tablette et Mobile directement depuis la barre d&#39;outils en haut pour tester le responsive de votre page.</p></div><h2 id="🔴-zone-3-—-le-panneau-de-droite-les-proprietes-du-composant" tabindex="-1">🔴 Zone 3 — Le panneau de droite : les propriétés du composant <a class="header-anchor" href="#🔴-zone-3-—-le-panneau-de-droite-les-proprietes-du-composant" aria-label="Permalink to &quot;🔴 Zone 3 — Le panneau de droite : les propriétés du composant&quot;">​</a></h2><p>Le panneau de droite s&#39;affiche uniquement lorsqu&#39;un composant est sélectionné dans la zone centrale. C&#39;est ici que vous configurez et personnalisez chaque composant.</p><h3 id="ce-que-vous-y-trouvez" tabindex="-1">Ce que vous y trouvez : <a class="header-anchor" href="#ce-que-vous-y-trouvez" aria-label="Permalink to &quot;Ce que vous y trouvez :&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Onglet</th><th>Contenu</th></tr></thead><tbody><tr><td><strong>Contenu</strong></td><td>Les champs éditables du composant (texte, image, lien…)</td></tr><tr><td><strong>Style</strong></td><td>Les options visuelles (couleurs, espacements, typographie…)</td></tr><tr><td><strong>Comportement</strong></td><td>Les options d&#39;animation, de visibilité conditionnelle…</td></tr><tr><td><strong>Avancé</strong></td><td>Les classes CSS personnalisées, attributs HTML...</td></tr></tbody></table><h3 id="exemple-concret-—-composant-hero-selectionne" tabindex="-1">Exemple concret — Composant &quot;Hero&quot; sélectionné : <a class="header-anchor" href="#exemple-concret-—-composant-hero-selectionne" aria-label="Permalink to &quot;Exemple concret — Composant &quot;Hero&quot; sélectionné :&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────┐</span></span>
<span class="line"><span>│  ⚙️ Propriétés : Hero        │</span></span>
<span class="line"><span>├─────────────────────────────┤</span></span>
<span class="line"><span>│ CONTENU                     │</span></span>
<span class="line"><span>│  Titre : [______________]   │</span></span>
<span class="line"><span>│  Sous-titre : [__________]  │</span></span>
<span class="line"><span>│  Image de fond : [📷]       │</span></span>
<span class="line"><span>│  Bouton CTA : [__________]  │</span></span>
<span class="line"><span>├─────────────────────────────┤</span></span>
<span class="line"><span>│ STYLE                       │</span></span>
<span class="line"><span>│  Hauteur : [___] px         │</span></span>
<span class="line"><span>│  Alignement texte : [⬛⬛⬛] │</span></span>
<span class="line"><span>│  Couleur overlay : [🎨]     │</span></span>
<span class="line"><span>└─────────────────────────────┘</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">⚠️ Important :</p><p>les propriétés disponibles dépendent de la définition du composant SDC (dans son fichier .component.yml). Plus un composant est bien défini, plus il offre d&#39;options de personnalisation dans ce panneau.</p></div><h3 id="🔧-la-barre-d-outils-du-haut" tabindex="-1">🔧 La barre d&#39;outils du haut <a class="header-anchor" href="#🔧-la-barre-d-outils-du-haut" aria-label="Permalink to &quot;🔧 La barre d&#39;outils du haut&quot;">​</a></h3><p>En plus des 3 panneaux, la barre d&#39;outils supérieure offre des actions globales sur la page :</p><table tabindex="0"><thead><tr><th>Bouton</th><th>Action</th></tr></thead><tbody><tr><td><strong>Annuler / Rétablir</strong></td><td>↩️ Défaire ou refaire une action</td></tr><tr><td><strong>Prévisualiser</strong></td><td>Voir la page comme un visiteur, hors éditeur</td></tr><tr><td><strong>Responsive</strong></td><td>Basculer entre Desktop / Tablette / Mobile</td></tr><tr><td><strong>Sauvegarder</strong></td><td>Enregistrer les modifications</td></tr><tr><td><strong>Publier</strong></td><td>Rendre la page visible sur le site</td></tr></tbody></table>`,30)]))}const m=s(o,[["render",r]]);export{h as __pageData,m as default};
